            ContentJson = """{"title":"Dashboard Widgets Catalog","groups":[{"heading":"Job Cards","items":[{"label":"Today's Tasks","value":"Your assigned jobs, overdue first, then active, upcoming, and completed. Overdue rows are red. Click a row to open the job's details. A link takes you to the board. Available when jobs are turned on."},{"label":"Jobs by Stage","value":"One bar per board stage — the busiest stage has the longest bar and the rest are sized against it, with the count shown next to each. See where work is piling up without opening the board. Available when jobs are turned on."},{"label":"Team Load","value":"One row per teammate with their name, a bar showing how busy they are versus how much they can take on, and their current task count. Shows how work is spread out, with a link to time tracking. Available when jobs are turned on."},{"label":"Deadlines","value":"Upcoming due dates with the job number, description, and date; overdue ones are flagged. Includes a link to the calendar. Available when jobs are turned on."}]},{"heading":"Pipeline & Planning Cards","items":[{"label":"Open Orders","value":"Total open sales orders as a headline number, split into Confirmed, In Production, and Partially Shipped. A link takes you to all orders. Available when sales orders are turned on."},{"label":"Cycle Progress","value":"How far along your current planning cycle is: a progress bar, how many entries are done out of the total with a percentage, a days-left or Overdue label, and the first few entries with checkmarks. Includes a link to planning cycles. Available when planning is turned on."},{"label":"Margin Summary","value":"Average margin percentage plus revenue, cost, and margin totals for recent jobs. Appears only when Forge handles your accounting."}]},{"heading":"Personal & Follow-up Cards","items":[{"label":"End of Day","value":"A place to jot down your top 3 priorities for tomorrow. Type them and Save; the card then shows your note with an Edit button. Saved for the day. Available when time tracking is turned on."},{"label":"Action Items","value":"Follow-ups the system raises for you (a quote about to expire, a stale lead, a past-due invoice, a delivery at risk, maintenance due, a failed quality check, a return received, and more). Each row links to the record it's about, shows a due date (overdue flagged), and has a checkmark to complete it and an X to dismiss it. Shows a friendly message when there's nothing to do."},{"label":"Activity","value":"A feed of recent activity across the system. Always available."}]},{"heading":"Inventory Card","items":[{"label":"Inventory Snapshot","value":"Part count, total on hand, and a low-stock count that turns an alert color when parts drop to or below their minimum level; the affected parts are listed with their current versus minimum quantities. Includes a link to inventory. This is the main card on an inventory-only install. Available when inventory is turned on."}]},{"heading":"Which Cards You Can Use","items":[{"label":"Depends on your install","value":"Each card is tied to a part of Forge. A card only shows up on your dashboard — and in the Add Widget menu — if that part is turned on for your install. An inventory-only install shows the Inventory Snapshot instead of the job numbers."},{"label":"Add a hidden card","value":"Turn on Customize, open the Add Widget menu, and pick any available card that isn't on your dashboard yet."},{"label":"Standard layout","value":"New dashboards start with the full set of available cards in a standard arrangement. The Reset button (in edit mode) puts this back any time."}]},{"heading":"Card Controls","items":[{"label":"Title & icon","value":"Every card has its title and icon across the top."},{"label":"See-all link","value":"Cards that summarize a bigger area show a link in their header (such as 'View board', 'All orders', 'Planning cycles', or 'View inventory') that jumps to the full feature."},{"label":"Remove (X)","value":"Shows only in edit mode — removes the card from your dashboard. Add it back later from the Add Widget menu."},{"label":"When there's no data","value":"A card with nothing to show displays a friendly message instead of a blank space — for example, Today's Tasks with no assignments, or Action Items with nothing outstanding."}]}]}"""
